                                    id integer PRIMARY KEY,
                                    name text NOT NULL,
                                    description text
                                );"""
        try:
            c = self.conn.cursor()
            c.execute(create_table_sql)
            print(f"Table {table_name} created")
        except Error as e:
            print(e)

    def insert_data(self, table_name, data):
        insert_data_sql = f"""INSERT INTO {table_name}(name, description)
                             VALUES(?,?)"""
        try:
            c = self.conn.cursor()
            c.execute(insert_data_sql, data)
            self.conn.commit()
            print(f"Data inserted into {table_name} table")
        except Error as e:
            print(e)

    def delete_data(self, table_name, id):
        delete_data_sql = f"""DELETE FROM {table_name}
                             WHERE id=?"""
