class NetworkSimulator:
    def __init__(self):
        self.nodes = {}
        self.connections = {}

    def add_node(self, node_id):
        if node_id not in self.nodes:
            self.nodes[node_id] = []
            self.connections[node_id] = []

    def add_connection(self, node1, node2):
        if node1 in self.nodes and node2 in self.nodes:
            self.nodes[node1].append(node2)
            self.nodes[node2].append(node1)
            self.connections[node1].append(node2)
            self.connections[node2].append(node1)

    def simulate(self, start_node, end_node):
        visited = set()
        queue = [(start_node, [start_node])]
        while queue:
            node, path = queue.pop(0)
            if node not in visited:
                if node == end_node:
                    return path
                visited.add(node)
                for neighbor in self.nodes[node]:
                    if neighbor not in visited:
                        queue.append((neighbor, path + [neighbor]))
        return None

    def get_shortest_path(self, start_node, end_node):
        return self.simulate(start_node, end_node)

    def get_all_paths(self, start_node, end_node):
        all_paths = []
        def dfs(node, path):
            if node == end_node:
                all_paths.append(path)
            else:
                for neighbor in self.nodes[node]:
                    if neighbor not in path:
                        dfs(neighbor, path + [neighbor])
        dfs(start_node, [start_node])
        return all_paths

    def get_node_degree(self, node):
        return len(self.connections[node])

    def get_network_degree(self):
        return sum(len(self.connections[node]) for node in self.nodes) // 2

    def get_clustering_coefficient(self, node):
        neighbors = self.nodes[node]
        num_neighbors = len(neighbors)
        num_edges = sum(1 for i in range(num_neighbors) for j in range(i + 1, num_neighbors) if neighbors[j] in self.connections[neighbors[i]])
        return 2 * num_edges / (num_neighbors * (num_neighbors - 1)) if num_neighbors > 1 else 0

    def get_average_clustering_coefficient(self):
        return sum(self.get_clustering_coefficient(node) for node in self.nodes) / len(self.nodes)

network = NetworkSimulator()
